# Deobfuscated Code

Here's the deobfuscated version with explanations:

```javascript
// Constants for physics simulation
const TWO_PI = 6.283;
const GOLDEN_RATIO = 1.618;
const SQRT_2 = 0.707;

// Configuration parameters
const config = {
  attraction: 4000,
  springStiffness: 0.004,
  amplification: 0.92,
  centerForce: 0.0003,
  maxParticles: 40,
  streamDecay: 0.04,
  theta: 0.06
};

// Define nodes/particles in the network
const nodes = [
  { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Define spring connections between nodes
const springs = [
  { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'beta', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera/view state
let camera = { x: 400, y: 300, zoom: 1 };
let targetCamera = { x: 400, y: 300, zoom: 1 };

// Particle system for effects
let particles = [];

function findNode(id) {
  return nodes.find(n => n.id === id);
}

function updatePhysics() {
  // Calculate repulsive forces between all nodes (N-body simulation)
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const dx = nodes[i].x - nodes[j].x;
      const dy = nodes[i].y - nodes[j].y;
      const distance = Math.sqrt(dx*dx + dy*dy) || 1;
      const force = config.attraction / (distance * distance);
      const fx = (dx / distance) * force;
      const fy = (dy / distance) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // Apply spring forces (attractive forces along edges)
  for (let spring of springs) {
    const nodeA = findNode(spring.a);
    const nodeB = findNode(spring.b);
    if (!nodeA || !nodeB) continue;

    const dx = nodeB.x - nodeA.x;
    const dy = nodeB.y - nodeA.y;
    const distance = Math.sqrt(dx*dx + dy*dy) || 1;
    const displacement = distance - spring.rest;
    const force = (spring.k || config.springStiffness) * displacement;

    nodeA.vx += (dx / distance) * force;
    nodeA.vy += (dy / distance) * force;
    nodeB.vx -= (dx / distance) * force;
    nodeB.vy -= (dy / distance) * force;
  }

  // Apply damping and center-pull forces
  for (let node of nodes) {
    node.vx *= config.amplification;
    node.vy *= config.amplification;
    node.vx += (400 - node.x) * config.centerForce;
    node.vy += (300 - node.y) * config.centerForce;
    node.x += node.vx;
    node.y += node.vy;
  }
}

function emitParticles() {
  if (particles.length >= config.maxParticles) return;

  const source = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TWO_PI;
  const speed = 0.3 + Math.random() * SQRT_2;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT_2
  });
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    let p = particles[i];
    p.age++;
    p.vx *= 1 - config.streamDecay * 0.125;
    p.vy *= 1 - config.streamDecay * 0.125;
    p.x += p.vx;
    p.y += p.vy;

    if (p.age > p.maxAge) {
      particles.splice(i, 1);
    }
  }
}

function updateCamera() {
  camera.x += (targetCamera.x - camera.x) * config.theta;
  camera.y += (targetCamera.y - camera.y) * config.theta;
  camera.zoom += (targetCamera.zoom - camera.zoom) * config.theta;
}

function animate() {
  updatePhysics();
  updateParticles();
  updateCamera();

  if (frameCount % 3 === 0) {
    emitParticles();
  }
  frameCount++;
}

setInterval(animate, 16);
```

## What It Does

This is a **force-directed graph physics simulation** that:

1. **Simulates a network graph** with nodes connected by springs
2. **Applies physics forces**:
   - Repulsive forces between all nodes (keeps them apart)
   - Spring forces along connections (keeps connected nodes together)
   - Damping and center-pull (stabilizes the system)
3. **Creates particle effects** that emit from nodes and decay over time
4. **Animates a camera** that smoothly follows the network's center
5. **Runs continuously** at ~60 FPS (16ms intervals)

This type of simulation is commonly used for visualizing networks, social graphs, molecular structures, or interactive force-directed layouts in data visualization tools.
